const xml = $input.first().json.data || $input.first().json.body || '';
const staleDays = $('Site Configuration').first().json.staleDays || 180;
const alertEmail = $('Site Configuration').first().json.alertEmail;

// Parse URLs and lastmod dates from sitemap XML
const urlRegex = /<url>([\s\S]*?)<\/url>/g;
const locRegex = /<loc>([^<]+)<\/loc>/;
const lastmodRegex = /<lastmod>([^<]+)<\/lastmod>/;

const pages = [];
let match;

while ((match = urlRegex.exec(xml)) !== null) {
  const block = match[1];
  const locMatch = block.match(locRegex);
  const lastmodMatch = block.match(lastmodRegex);

  if (locMatch) {
    const url = locMatch[1];
    const lastmod = lastmodMatch ? lastmodMatch[1] : null;

    let isStale = false;
    let daysSinceUpdate = null;

    if (lastmod) {
      const lastModDate = new Date(lastmod);
      const now = new Date();
      daysSinceUpdate = Math.floor((now - lastModDate) / (1000 * 60 * 60 * 24));
      isStale = daysSinceUpdate > staleDays;
    } else {
      // No lastmod = potentially stale, flag for review
      isStale = true;
      daysSinceUpdate = -1; // Unknown
    }

    if (isStale) {
      pages.push({
        json: {
          url,
          lastModified: lastmod || 'unknown',
          daysSinceUpdate,
          staleDays,
          alertEmail
        }
      });
    }
  }
}

// Sort by staleness (most stale first)
pages.sort((a, b) => b.json.daysSinceUpdate - a.json.daysSinceUpdate);

// Limit to top 20 for AI analysis
return pages.slice(0, 20);

