const items = $input.first().json.data || [];
const staleDays = $('Site Configuration').first().json.staleDays || 180;
const totalPages = items.length;

let html = `
<div style="font-family: Arial, sans-serif; max-width: 680px; margin: 0 auto; color: #333;">
  <h1 style="font-size: 22px; border-bottom: 2px solid #333; padding-bottom: 10px;">Stale Content Audit Report</h1>
  <p style="font-size: 16px; color: #555;">Pages flagged for review: <strong>${totalPages}</strong></p>
`;

if (totalPages === 0) {
  html += '<p style="color: #2a9d2a;">No stale pages found. Your content is looking fresh!</p>';
} else {
  for (let i = 0; i < totalPages; i++) {
    const page = items[i];
    const url = page.page_url || 'Unknown';
    const urlPath = url.replace(/^https?:\/\/[^/]+/, '') || '/';
    const days = page.days_since_update;
    const daysText = days && days > 0 ? `${days} days ago` : 'Unknown';
    const review = page.ai_review || 'No review available';

    // Color code by staleness
    let badgeColor = '#e67e22'; // orange default
    if (days > 365) badgeColor = '#e74c3c'; // red
    else if (days > 270) badgeColor = '#e67e22'; // orange
    else badgeColor = '#f1c40f'; // yellow

    html += `
  <div style="background: #f9f9f9; border-left: 4px solid ${badgeColor}; padding: 16px 20px; margin: 16px 0; border-radius: 4px;">
    <h3 style="margin: 0 0 6px 0; font-size: 16px;">${i + 1}. ${urlPath}</h3>
    <p style="margin: 0 0 10px 0; font-size: 13px; color: #888;">Last updated: <strong style="color: ${badgeColor};">${daysText}</strong></p>
    <p style="margin: 0; font-size: 14px; line-height: 1.5; color: #444;">${review}</p>
  </div>`;
  }
}

html += `
  <hr style="border: none; border-top: 1px solid #ddd; margin: 24px 0;" />
  <p style="font-size: 13px; color: #999;">This report checks all pages in your sitemap not updated in over ${staleDays} days.<br/>Full details with AI analysis are in your Google Sheet.</p>
  <p style="font-size: 12px; color: #bbb;">Generated by Stale Content Detector</p>
</div>`;

return [{ json: { emailBody: html, totalPages } }];
